query:
process where event.action == "start" and
  (
    /* Detect process-access events toward protected processes */
    process.name : ("winlogon.exe", "lsass.exe", "csrss.exe", "services.exe")
  ) and
  /* Source is not a known legitimate system process */
  not process.parent.name : (
    "MsMpEng.exe", "svchost.exe", "WmiPrvSE.exe",
    "taskmgr.exe", "csrss.exe", "wininit.exe",
    "smss.exe", "winlogon.exe"
  )

sequence by host.id with maxspan=5m
  /* Stage 1: Process enumeration or access to SYSTEM processes */
  [process where event.action == "start" and
    process.name : ("winlogon.exe", "lsass.exe") and
    not process.parent.name : ("wininit.exe", "smss.exe", "svchost.exe", "csrss.exe")
  ]
  /* Stage 2: Encrypted file created - rename/append extension phase */
  [file where event.action == "creation" and
    (
      file.path : ("*.encrypted", "*.locked", "*.crypted", "*.enc",
                    "*.crypt", "*.ransom", "*.WNCRY", "*.ryk", "*.lck")
      or
      file.name : ("MASTER_KEY.key", "MASTER_KEY.txt", "key.bin")
    )
  ]
